var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"1시간 전…… 그러니까, 협정 세계시를 기준으로 1시간 전에 벌어진 일이요.","JPN":"1時間前……つまり、協定世界時を基準に1時間前に起こったことだ。","ENG":"This happened an hour ago. Based on the agreed-upon world standard time, that is.","TWN":"1小時前……總之就是以世界協調時間為準，1小時前發生的事啦！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"망할 해적 놈들한테 우리 알파트릭스 그룹 소유의 연구선이 나포되었다더군.","JPN":"海賊に我がアルファトリックスグループ所有の研究船が拿捕されたそうだ。","ENG":"Some accursed pirates have stolen the Alphatrix group's research ship.","TWN":"那些該死的海盜，竟然搶走我們阿爾法崔克斯集團的研究船！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"함선 한 척 따윈 아깝지 않지만, 그 안에는 우리 그룹의 연구 데이터가 잔뜩 들어 있어.","JPN":"艦船一隻くらいくれてやってもいいが、その中には我が社の研究データが大量に搭載されている。","ENG":"I don't care about the ship, but I do care about the research data that it carries in it.","TWN":"損失區區一艘艦船沒什麼好心疼的，但那艘船裡面都是我們集團的研究資料。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"자, 여기까지 들었으면 의뢰 내용이 뭔지 대충 짐작 가겠지.","JPN":"さあ、ここまで聞いたなら依頼内容の見当がついただろう。","ENG":"There. I'm sure you can figure out the rest of my request.","TWN":"聽到這裡，你應該知道委託的內容是什麼了吧？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"연구선을 되찾아 오시오. 최대한 온전한 상태로 말이야.","JPN":"研究船を取り戻しなさい。できるだけ完全な状態で。","ENG":"Retrieve the research ship. With minimal damage.","TWN":"幫我搶回研究船，並且要盡量維持它的完整！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그러면 당신네 같은 조그만 회사는 상상도 못할 거액을 안겨 주겠소.","JPN":"そうすれば、お前たちのような小さな会社では想像もつかない巨額を支払う。","ENG":"If you do, I'll give you the kind of money that you'd never get in a small company like this.","TWN":"只要幫我把研究船搶回來，我會給你們這種小公司從沒見過的巨款作為酬勞。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"……아, 참고 삼아 말해두지.","JPN":"……ああ、これは参考程度だが。","ENG":"Ah, just so you know...","TWN":"對了……這些話你們聽聽就好。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"놈들은 관리국 연합 함대가 토벌했던 스캐빈저들의 잔당이오.","JPN":"奴らは管理局連合艦隊が討伐したスカベンジャーの残党だ。","ENG":"They were the remnants of the Scavengers subjugated by the Administration Coalition Fleet.","TWN":"那些傢伙就是管理局聯合艦隊曾經討伐過的清道夫餘黨。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"당신네 용병들은 해적 잡는 해적들이라고 두려워하지만, 그래 봐야 이빨 빠진 호랑이야.","JPN":"傭兵の間では海賊を狩る海賊と恐れられているようだが、しょせん残党は残党。","ENG":"You mercenaries may be afraid of them because they're the pirates that catch pirates. But I'm telling you, they're just toothless tigers.","TWN":"雖然你們這些傭兵其實也跟海盜差不多，但還是比真正的海盜安全一點啦！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그럼 좋은 소식 기다리겠소.","JPN":"では、いい知らせを待っているぞ。","ENG":"Now, I'll wait for the good news.","TWN":"那就等你們的好消息囉！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"단방향 통신으로 인사드리는 건 간만인 것 같네요, 사장님.","JPN":"単方向通信で挨拶するのは久しぶりですね、社長。","ENG":"Boss, it's been a long time since we last talked in simplex mode.","TWN":"老闆好～好像很久沒透過單工通訊跟您問好了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"공유해 주신 메시지는 확인했습니다.","JPN":"共有していただいたメッセージは確認しました。","ENG":"I've checked the message you shared.","TWN":"您發來的訊息我收到了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"아시다시피, 현재 펜릴 소대 및 서윤 소대장 모두 다른 임무로 부재 중입니다.","JPN":"ご存知のように、現在フェンリル小隊およびアオイ・シズカ小隊長は別の任務で不在です。","ENG":"As you know, both the Fenrir Squad and Commander Seo Yoon are away on different missions.","TWN":"您也知道，現在芬里爾小隊和徐芸小隊長正外出執行任務中。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그래도 긴급 의뢰라고 하셔서, 일단 대기하고 있던 저희 소대원들을 소집했어요.","JPN":"しかし緊急依頼とおっしゃったので、とりあえず待機していた小隊員を招集しました。","ENG":"As you said this is urgent, I've gathered our available squad members.","TWN":"但又是緊急委託，所以我就招集了待命中的小隊員。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"코핀 함도 작전 중이라 렌탈 업체에서 함선도 한 척 대여해 왔고요.","JPN":"コフィン艦も作戦中なので、レンタル業者から艦船も1隻レンタルしておきました。","ENG":"Because even the Coffin is away on a mission, I've also rented a ship from a rental company.","TWN":"然後科芬艦也在作戰中，所以我就跟出租公司租了一艘艦船。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"다이브도 힘겨워하는 구형 함선이라, 결과는 장담 못 드리겠지만요.","JPN":"ダイブすらギリギリ耐えられる程度の旧型艦船ですから、性能は何とも言えませんが。","ENG":"I'm not sure if this old model can Dive, though.","TWN":"可是是連躍入都有困難的舊型艦船，所以結論就是無法保證打得贏。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그보다…… 의뢰주인 알파트릭스 그룹의 부회장에 대해서입니다만.","JPN":"それより……依頼主のアルファトリックスグループの副会長のことですが。","ENG":"By the way... about our client, the vice chairman of Alphatrix Group.","TWN":"先不管輸贏的事……說到委託人阿爾法崔克斯集團的副會長，"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"이미 저희 외에도 여러 태스크포스에 같은 의뢰를 한 정황이 있습니다.","JPN":"すでに私たち以外にも複数のタスクフォースカンパニーに同じ依頼を出しているとの情報があります。","ENG":"He's hired several other TASKFORCE companies for the same purpose.","TWN":"除了我們之外，他也有委託其他的特遣勢力。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"국제적인 대기업이 연구선 한 척 때문에 이렇게 많은 인력을 동원하다니, 조금 수상하네요.","JPN":"国際的な大手企業が研究船1隻のためにここまで多くの人員を動員するとは、少し怪しいですね。","ENG":"It's a bit suspicious that a big multi-national corporation is outsourcing so much help for the sake of a single research ship.","TWN":"一個規模這麼大的國際企業，竟然為了區區一艘研究船如此大費周章，不覺得有點奇怪嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};